async (params, browser) => {
  // Open full credits page
  await browser.open(`https://www.imdb.com/title/${params.title_id}/fullcredits/`)

  // Wait for credits page
  await browser.waitForSelector('table.cast_list, [class*=\'fullcredits\'], [class*=\'Credits\'], .ipc-metadata-list', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll through credits
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract cast and crew
  const cast_data = await browser.evaluate(`const cast = []; const castRows = document.querySelectorAll('table.cast_list tr, [data-testid="title-cast-item"]'); castRows.forEach(function(row) { const nameEl = row.querySelector('td:nth-child(2) a, [data-testid="title-cast-item__actor"], a[href*="/name/"]'); const charEl = row.querySelector('td.character, [data-testid="cast-item-characters-link"], [class*="character"]'); const imgEl = row.querySelector('img'); if (nameEl) { cast.push({ name: nameEl.textContent.trim(), character: charEl ? charEl.textContent.trim().replace(/\s+/g, ' ') : '', image: imgEl ? imgEl.getAttribute('src') : '', url: nameEl.href || '' }); } }); const crew = {}; const headers = document.querySelectorAll('#fullcredits_content > h4, [class*="Credits"] h4, .ipc-title__text'); headers.forEach(function(h) { const role = h.textContent.trim().replace(/\s+/g, ' '); const table = h.nextElementSibling; if (table && table.tagName === 'TABLE') { const names = []; table.querySelectorAll('tr').forEach(function(row) { const nameEl = row.querySelector('a[href*="/name/"]'); if (nameEl) names.push(nameEl.textContent.trim()); }); if (names.length > 0) crew[role] = names.slice(0, 10); } }); const titleEl = document.querySelector('h3 a, [class*="parent"] a, [data-testid="hero-title-block__title"]'); const titleIdMatch = window.location.pathname.match(/\/title\/(tt\d+)/); return { title_id: titleIdMatch ? titleIdMatch[1] : '', title: titleEl ? titleEl.textContent.trim() : '', cast_count: cast.length, cast: cast.slice(0, 30), crew: crew, url: window.location.href }`)

  return cast_data
}
